package eventlog

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40010/event/userevent"
	"github.com/arminguenther/xeruspower-go/v40010/idl"
	"github.com/arminguenther/xeruspower-go/v40010/logging/log"
)

// Event log cleared event
type ClearedEvent interface {
	userevent.UserEvent
	isClearedEvent()
}

// Device event log interface
type EventLog interface {
	idl.Object

	// Clear the event log.
	Clear(ctx context.Context) error

	// Get info about the event log.
	//
	//	@return log info
	GetInfo(ctx context.Context) (log.Info, error)

	// Fetch a chunk from the event log.
	//
	// For details regarding the behavior of this method refer to the description
	// of the logging module in Log.idl.
	//
	//	@param idRef      First log id to fetch
	//	@param count      Number of entries to fetch
	//	@param direction  Range direction
	//	@param categories Event categories to filter for. When empty then filtering is disabled.
	//
	//	@return log chunk
	GetChunk(ctx context.Context, refId int32, count int32, direction log.RangeDirection, categories []string) (log.Chunk, error)
}
